      "env": {
        "HI_AI_FEATURES": "ast,prompt,nlp,semantic"
      }
    }
  }
}
```

**3. 호환성 확인**

```typescript
// 기존 도구는 모두 호환
const complexity = await tools.execute("analyze_complexity", { code });

// 새 도구 사용 가능
const symbol = await tools.execute("find_symbol", { name: "MyClass" });
